# 颜色说明：
# 严格按照原图网格逐格提取，每个格子一个像素
# HT = 黑色 (0,0,0)
# 灰度数值越大越亮：H7(60), H4(100), H(140)
# A20 = 金色黄色 (255, 215, 0)
# F4 = 红色 (255, 50, 50)
# A7 = 浅橙色皮肤 (255, 165, 100)
# O15 = 棕色手臂 (198, 142, 90)
# 短裤 = 浅灰色 (200, 200, 200)


class PixelPreviewWidget(QWidget):
    """Preview widget to display the pixel art."""

    def __init__(self, pixel_data: List[List[Tuple[int, int, int] | None]], parent=None):
        super().__init__(parent)
        self._pixel_data = pixel_data
        self._scale = 12  # Scale each pixel to 12x12 pixels for good visibility
        self._grid_height = len(pixel_data)
        self._grid_width = max(len(row) for row in pixel_data) if pixel_data else 0

        # Calculate window size
        window_width = self._grid_width * self._scale + 40
        window_height = self._grid_height * self._scale + 40
        self.setFixedSize(window_width, window_height)
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)
        self.setWindowTitle("iKun Pixel Art Preview")

    def paintEvent(self, event):
        """Draw the pixel art."""
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, False)

        # Center the pixel art
        offset_x = (self.width() - self._grid_width * self._scale) // 2
        offset_y = (self.height() - self._grid_height * self._scale) // 2

        # Draw each pixel
        for row_idx, row in enumerate(self._pixel_data):
            for col_idx, color_info in enumerate(row):
                if color_info is None:
                    continue
                r, g, b = color_info
                color = QColor(r, g, b)
                x = offset_x + col_idx * self._scale
                y = offset_y + row_idx * self._scale
                painter.fillRect(x, y, self._scale, self._scale, color)

                # Add slight border between pixels
                painter.setPen(QPen(QColor(255, 255, 255, 20), 1))
                painter.drawRect(x, y, self._scale, self._scale)

        painter.end()


class PreviewWindow(QMainWindow):
    """Main preview window."""

    def __init__(self, pixel_data: List[List[Tuple[int, int, int] | None]]):
        super().__init__()
        self.setWindowTitle("iKun Pixel Art Preview")
        self.setWindowFlags(Qt.WindowType.Window)
        self._preview_widget = PixelPreviewWidget(pixel_data, self)
        self.setCentralWidget(self._preview_widget)
        self.resize(self._preview_widget.size())


def main():
    """Run the preview."""
    app = QApplication(sys.argv)
    window = PreviewWindow(IKUN_PIXEL_DATA)
    window.show()
    sys.exit(app.exec())


if __name__ == "__main__":
    main()
